def range_summary(nums):
    if not nums: return ''
    sorted_nums = sorted(set(nums))
    result = []
    start = None
    for num in sorted_nums:
        if start is None or num > start + 1:
            if start is not None:
                result.append(f'{start}-{num-1}' if num - start > 1 else f'{start}')
            start = num
    return ','.join(result)
